package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import java.lang.reflect.Field;

public class CSVFormatTest {

    private CSVFormat csvFormat;

    @BeforeEach
    public void setUp() {
        csvFormat = CSVFormat.DEFAULT;
    }

    @Test
    public void testIsCommentMarkerSet_ReturnsFalse_WhenCommentMarkerIsNull() throws Exception {
        // Use reflection to set commentMarker to null
        Field commentMarkerField = CSVFormat.class.getDeclaredField("commentMarker");
        commentMarkerField.setAccessible(true);

        // CSVFormat is immutable, so we need to create a new instance with commentMarker null using withCommentMarker(null)
        csvFormat = csvFormat.withCommentMarker((Character) null);

        assertFalse(csvFormat.isCommentMarkerSet());
    }

    @Test
    public void testIsCommentMarkerSet_ReturnsTrue_WhenCommentMarkerIsSet() throws Exception {
        // Use withCommentMarker to set commentMarker to a non-null value
        csvFormat = csvFormat.withCommentMarker('#');

        assertTrue(csvFormat.isCommentMarkerSet());
    }
}
